import{_ as a,C as s,o,c as l,E as i,w as r,a as n,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Moving to Sweden","description":"Immigration pathways and relocation guide for transgender people moving to Sweden","frontmatter":{"layout":"doc","title":"Moving to Sweden","description":"Immigration pathways and relocation guide for transgender people moving to Sweden"},"headers":[],"relativePath":"europe/sweden/moving-there.md","filePath":"europe/sweden/moving-there.md","lastUpdated":null}'),h={name:"europe/sweden/moving-there.md"};function g(c,e,u,m,f,p){const t=s("Badge");return o(),l("div",null,[i(t,{variant:"green"},{default:r(()=>[...e[0]||(e[0]=[n("EU Free Movement",-1)])]),_:1}),i(t,{variant:"yellow"},{default:r(()=>[...e[1]||(e[1]=[n("High Swedish Requirement",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="moving-to-sweden" tabindex="-1">Moving to Sweden <a class="header-anchor" href="#moving-to-sweden" aria-label="Permalink to &quot;Moving to Sweden&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eu-eea-swiss-citizens" tabindex="-1">EU/EEA/Swiss Citizens <a class="header-anchor" href="#eu-eea-swiss-citizens" aria-label="Permalink to &quot;EU/EEA/Swiss Citizens&quot;">​</a></h3><p>Sweden grants full free movement rights to EU/EEA/Swiss citizens. Registration with the Swedish Tax Agency (Skatteverket) is required for stays over one year.</p><h3 id="non-eu-citizens" tabindex="-1">Non-EU Citizens <a class="header-anchor" href="#non-eu-citizens" aria-label="Permalink to &quot;Non-EU Citizens&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Visa</td><td>For employment with Swedish employer</td><td>Job offer, salary ≥ ~€26,000/year, union-approved terms</td><td>2 years, renewable</td></tr><tr><td>EU Blue Card</td><td>For highly qualified workers</td><td>Degree + salary threshold (approx. €55,000/year)</td><td>2 years, renewable</td></tr><tr><td>Self-Employed Visa</td><td>For business owners/freelancers</td><td>Business plan, sufficient funds, client base in Sweden</td><td>2 years, renewable</td></tr><tr><td>Family Reunification</td><td>For family of Swedish residents</td><td>Relationship proof, sufficient income (€8,800+/year after housing)</td><td>2 years, renewable</td></tr><tr><td>Student Visa</td><td>For full-time study</td><td>University acceptance, funds proof (€9,000+/year)</td><td>Duration of studies</td></tr><tr><td>Research Visa</td><td>For researchers</td><td>Host institution agreement</td><td>2 years, renewable</td></tr></tbody></table><h2 id="key-relocation-steps" tabindex="-1">Key Relocation Steps <a class="header-anchor" href="#key-relocation-steps" aria-label="Permalink to &quot;Key Relocation Steps&quot;">​</a></h2><ol><li><strong>Secure a job or study place</strong> — Job offer is the most common path for non-EU citizens</li><li><strong>Apply for residence permit</strong> — Through the Swedish Migration Agency (before arrival for non-EU)</li><li><strong>Register with Skatteverket</strong> — Get a personal identity number (personnummer)</li><li><strong>Find accommodation</strong> — Housing is competitive, especially in Stockholm and Gothenburg</li><li><strong>Open a bank account</strong> — Requires personnummer (BankID comes later)</li><li><strong>Register with a healthcare centre (vårdcentral)</strong> — For a GP</li><li><strong>Enrol in Swedish language courses (SFI)</strong> — Free for residents</li><li><strong>Join RFSL</strong> — For LGBTQ+ community support</li></ol><h2 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h2><p>Sweden has a high cost of living, particularly in major cities:</p><ul><li>Rent (1-bedroom): €900-1,500/month (Stockholm); €600-1,000 (Gothenburg/Malmö)</li><li>Groceries: €300-450/month</li><li>Public transport: €80-120/month pass</li><li>Health insurance: Public system, low costs (annual cap ~€240 for medications)</li><li>Second-hand market (Blocket, Myrorna) is excellent for affordable furniture</li></ul><h2 id="trans-specific-relocation-tips" tabindex="-1">Trans-Specific Relocation Tips <a class="header-anchor" href="#trans-specific-relocation-tips" aria-label="Permalink to &quot;Trans-Specific Relocation Tips&quot;">​</a></h2><ul><li><strong>Healthcare wait times are long</strong> — Register with a gender clinic immediately upon arrival</li><li><strong>Stockholm&#39;s ANOVA clinic</strong> has the longest wait times; consider Gothenburg or Umeå for shorter waits</li><li><strong>English is very widely spoken</strong> — nearly all Swedes speak fluent English</li><li><strong>Swedish is essential for integration</strong> — and required for permanent residence and citizenship</li><li><strong>Bring medical records translated into Swedish</strong></li><li><strong>Carry at least 6 months of HRT medication</strong> given the long wait times for gender clinics</li><li><strong>Private HRT options</strong> are limited — Gender GP (UK-based) is used by some, but prescriptions may face issues</li><li><strong>High Swedish requirement for citizenship</strong> — C1 level language test required</li><li><strong>Sweden has a strong social safety net</strong> — unemployment benefits, parental leave, healthcare subsidies</li></ul><h2 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h2><ul><li><strong>Official language</strong>: Swedish</li><li><strong>English</strong> — Very widely spoken, over 90% fluency</li><li><strong>Swedish</strong> required for permanent residence (A2-B1) and citizenship (C1 — high requirement)</li><li><strong>SFI (Swedish for Immigrants)</strong> — Free language courses provided by municipalities</li><li>Swedish is one of the hardest requirements for naturalisation in the EU</li></ul><h2 id="citizenship-timeline" tabindex="-1">Citizenship Timeline <a class="header-anchor" href="#citizenship-timeline" aria-label="Permalink to &quot;Citizenship Timeline&quot;">​</a></h2><ul><li>5 years of continuous residence (EU/EEA citizens) or 5 years (non-EU citizens)</li><li>Must demonstrate Swedish language proficiency at C1 level</li><li>Good conduct requirement (no serious criminal record)</li><li>Citizenship interview may be required</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Migrationsverket (Swedish Migration Agency)</strong> — <a href="https://www.migrationsverket.se/" target="_blank" rel="noreferrer">migrationsverket.se</a></li><li><strong>Skatteverket</strong> — Population registration: <a href="https://www.skatteverket.se/" target="_blank" rel="noreferrer">skatteverket.se</a></li><li><strong>Arbetsförmedlingen</strong> — Employment services: <a href="https://www.arbetsformedlingen.se/" target="_blank" rel="noreferrer">arbetsformedlingen.se</a></li><li><strong>RFSL</strong> — LGBTQ+ rights organisation: <a href="https://www.rfsl.se/" target="_blank" rel="noreferrer">rfsl.se</a></li><li><strong>Transformering.se</strong> — Trans health guide: <a href="https://www.transformering.se/" target="_blank" rel="noreferrer">transformering.se</a></li><li><strong>1177 Vårdguiden</strong> — Healthcare guide: <a href="https://www.1177.se/" target="_blank" rel="noreferrer">1177.se</a></li></ul>',19))])}const b=a(h,[["render",g]]);export{y as __pageData,b as default};
